import React from "react";
import { Line } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { chartDatasets } from "@/types/chart";

type TLineChart = {
  myDatasets: chartDatasets[];
  myLabels: string[];
  chartTitle: string;
};

const LineChart = ({ myDatasets, myLabels, chartTitle }: TLineChart) => {
  ChartJS.register(
    CategoryScale,
    LinearScale,
    PointElement,
    LineElement,
    Title,
    Tooltip,
    Legend
  );
  const options = {
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: "bottom" as const,
      },
      title: {
        display: true,
        text: chartTitle,
      },
    },
  };

  //   const vlabels = [
  //     "January",
  //     "February",
  //     "March",
  //     "April",
  //     "May",
  //     "June",
  //     "July",
  //   ];

  const data = {
    myLabels,
    datasets: myDatasets,
  };
  return <Line options={options} data={data} />;
};

export default LineChart;
